#include <bits/stdc++.h>
using namespace std;
const int mod=80112002,N=5003;
int n,m,d[N][2],dp[N];
vector<int> g[N];
int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++){
        int u,v;
        scanf("%d%d",&u,&v);
        g[u].push_back(v);
        d[u][1]++,d[v][0]++;
    }
    for(int i=1;i<=n;i++){
        if(!d[i][1])
            g[i].push_back(n+1),d[n+1][0]++;
    }
    queue<int> s,t;
    for(int i=1;i<=n;i++)
        if(!d[i][0])
            t.push(i),dp[i]=1;
    while(t.size()){
        s.push(t.front());
        t.pop();
        int u=s.back(),len=g[u].size();
        for(int i=0;i<len;i++){
            if(!(--d[g[u][i]][0]))
                t.push(g[u][i]);
            dp[g[u][i]]+=dp[u],dp[g[u][i]]%=mod;
        }
    }
    printf("%d",dp[n+1]);
    return 0;
}
